import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Admin() {
  const [requests, setRequests] = useState([]);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const adminPassword = "admin123"; // आपका पासवर्ड

  const handleLogin = (e) => {
    e.preventDefault();
    if (password === adminPassword) {
      setIsLoggedIn(true);
      fetchData();
    } else {
      alert("Wrong Password!");
    }
  };

  const fetchData = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
    } catch (err) { console.error(err); }
  };

  if (!isLoggedIn) {
    return (
      <div className="container py-5 mt-5">
        <div className="row justify-content-center">
          <div className="col-md-4 text-center card shadow p-4 border-0">
            <h3>Admin Login</h3>
            <form onSubmit={handleLogin}>
              <input type="password" placeholder="Enter Password" dclassName="form-control my-3" value={password} onChange={(e) => setPassword(e.target.value)} />
              <button className="btn btn-dark w-100 fw-bold">Login to Dashboard</button>
            </form>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="container py-5">
      <div className="d-flex justify-content-between mb-4">
        <h2>Hire Requests Dashboard</h2>
        <button className="btn btn-outline-danger" onClick={() => setIsLoggedIn(false)}>Logout</button>
      </div>
      <div className="table-responsive shadow-sm p-3 bg-white rounded">
        <table className="table table-hover border">
          <thead className="table-primary">
            <tr>
              <th>Date</th><th>Client Name</th><th>Email</th><th>Service</th><th>Details</th>
            </tr>
          </thead>
          <tbody>
            {requests.map(req => (
              <tr key={req._id}>
                <td>{new Date(req.date).toLocaleDateString()}</td>
                <td className="fw-bold">{req.fullName}</td>
                <td>{req.email}</td>
                <td><span className="badge bg-info text-dark">{req.serviceType}</span></td>
                <td>{req.projectDetails}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
export default Admin;
